// Global shared resources
buffer[N]; // Bounded buffer of size N
semaphore empty = N; // Count of empty slots
semaphore full = 0; // Count of filled slots
mutex lock; // Mutual exclusion for buffer

// Producer thread code
function producer() {
 item = produce_item();
 wait(empty); // Decrement empty slot count

 lock.acquire(); // Enter critical section
 buffer[put_index] = item;
 put_index = (put_index + 1) % N;
 lock.release(); // Exit critical section

 signal(full); // Increment filled slot count
}

// Consumer thread code 
function consumer() {
 wait(full); // Decrement filled slot count

 lock.acquire(); // Enter critical section
 item = buffer[get_index];
 get_index = (get_index + 1) % N;
 lock.release(); // Exit critical section

 signal(empty); // Increment empty slot count
 consume_item(item);
}

// Shared state
#define BUFFER_SIZE 100
typedef struct {
 int buffer[BUFFER_SIZE];
 int count; // Number of items in buffer
 int put_idx; // Next slot to produce
 int get_idx; // Next slot to consume
} SharedBuffer;

SharedBuffer shared;
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
pthread_cond_t not_full = PTHREAD_COND_INITIALIZER;
pthread_cond_t not_empty = PTHREAD_COND_INITIALIZER;

// Producer function
void* producer(void* arg) {
 int item = produce_item();

 pthread_mutex_lock(&mutex);
 while (shared.count == BUFFER_SIZE) // While buffer full
 pthread_cond_wait(&not_full, &mutex); // Wait for space

 shared.buffer[shared.put_idx] = item;
 shared.put_idx = (shared.put_idx + 1) % BUFFER_SIZE;
 shared.count++;

 pthread_cond_signal(&not_empty); // Wake consumer if waiting
 pthread_mutex_unlock(&mutex);
}

// Consumer function
void* consumer(void* arg) {
 pthread_mutex_lock(&mutex);
 while (shared.count == 0) // While buffer empty
 pthread_cond_wait(&not_empty, &mutex); // Wait for items

 int item = shared.buffer[shared.get_idx];
 shared.get_idx = (shared.get_idx + 1) % BUFFER_SIZE;
 shared.count--;

 pthread_cond_signal(&not_full); // Wake producer if waiting
 pthread_mutex_unlock(&mutex);

 consume_item(item);
}

// Lock-free SPSC buffer
#define CAPACITY 1024
typedef struct {
 _Atomic int write_idx; // Atomic: next write position
 _Atomic int read_idx; // Atomic: next read position
 int data[CAPACITY];
} LockFreeBuffer;

LockFreeBuffer buf;

// Initialize
atomic_store(&buf.write_idx, 0);
atomic_store(&buf.read_idx, 0);

// Producer: returns 1 on success, 0 if buffer full
int produce(int item) {
 int w = atomic_load(&buf.write_idx);
 int r = atomic_load(&buf.read_idx);
 int next_w = (w + 1) % CAPACITY;

 if (next_w == r) // Buffer full
 return 0; // Cannot produce

 buf.data[w] = item; // Write data first (not strictly needed with CAS)

 // Try to advance write index
 // In real implementation: CAS loop for more robust solution
 atomic_store(&buf.write_idx, next_w);
 return 1;
}

// Consumer: returns 1 on success, 0 if buffer empty
int consume(int* item) {
 int w = atomic_load(&buf.write_idx);
 int r = atomic_load(&buf.read_idx);

 if (w == r) // Buffer empty
 return 0;

 *item = buf.data[r];
 int next_r = (r + 1) % CAPACITY;
 atomic_store(&buf.read_idx, next_r);
 return 1;
}
